body:
I have two verilog files. They should have the same result, but the SAT solver fails. Unclear to me why

## Steps to reproduce the issue

option1.v
```
module regfile2r1w_alt
  (input                   clk
  ,input [4-1:0]          waddr0
  ,input                  we0
  ,input [7-1:0]          din0
  ,input [4-1:0]          raddr0
  ,output [7-1:0]         q0
  ,output [7-1:0]         q1
  );

  reg [7-1:0] rf[2-1:0];

  reg [7-1:0] q0_next;
  always_comb begin
    if (we0 && raddr0 == waddr0)
      q0_next = din0;
    else
      q0_next = rf[raddr0];
  end

  always @(posedge clk) begin
    q0 <= q0_next;
  end

  always @(posedge clk) begin
    q1 <= q0_next;
  end

  always @(posedge clk) begin
    if (we0) begin
      rf[waddr0] <= din0;
    end
  end

endmodule
```

option2.v
```
module regfile2r1w_alt
  (input                   clk
  ,input [4-1:0]          waddr0
  ,input                  we0
  ,input [7-1:0]          din0
  ,input [4-1:0]          raddr0
  ,output [7-1:0]         q0
  ,output [7-1:0]         q1
  );

  reg [7-1:0] rf[2-1:0];

  reg [7-1:0] q0_next;
  always_comb begin
    if (we0 && raddr0 == waddr0)
      q0_next = din0;
    else
      q0_next = rf[raddr0];
  end
  always @(posedge clk) begin
    q0 <= q0_next;
  end

  reg [7-1:0] q1_next;
  always_comb begin
    if (we0 && raddr0 == waddr0)
      q1_next = din0;
    else
      q1_next = rf[raddr0];
  end
  always @(posedge clk) begin
    q1 <= q1_next;
  end

  always @(posedge clk) begin
    if (we0) begin
      rf[waddr0] <= din0;
    end
  end

endmodule
```

The script to check:
```
read_verilog -sv ./option1.v ; opt; prep; memory ; rename -top gold; design -stash gold;
read_verilog -sv ./option2.v ; opt; prep; memory ; rename -top gate; design -stash gate;
design -copy-from gold -as gold gold
design -copy-from gate -as gate gate

miter -equiv -make_assert -flatten gold gate equiv
hierarchy -top equiv
sat -prove-asserts -show-inputs -max 2 -verify -set-init-undef -ignore_unknown_cells equiv
```

